import { roundMultiplier } from '../lib/utils'
import {
  FRENZY_BASE, FRENZY_RAGE_MULT, MINION_ABSORPTION_MULT,
  BLOOD_THIRSTY_MULT_PER_STACK, VENOM_SPITTER_MULT_PER_STACK,
  PERFECTION_MULT_PER_STACK, STEALTH_MULT_PER_STACK,
  GOLDEN_CRITS_MULT_PER_STACK, GOLDEN_CRITS_BASE_PROC_CHANCE,
  ROYAL_PARRY_MULT_PER_STACK, SPELL_PIERCER_MULT_PER_STACK,
  SCOURGE_MULT_PER_STACK, SHARPSHOOTER_MULT_PER_STACK,
  VALOR_MULT_PER_STACK, GORECAST_MULT_PER_STACK,
  UNDEAD_MIGHT_MULT_PER_STACK, HIGHLANDER_MULT_PER_STACK,
  
  VENOM_EATER_DMG_MULT_PER_STACK, FEROCITY_TENACITY_MULT,
  SPIRIT_WINDS_TAILWIND_MULT, SPIRIT_WINDS_PER_STACK,
  GUARDIAN_SPIN_BASE, GUARDIAN_SPIN_MULT_PER_STACK,
  WILD_BOLT_MULT_PER_STACK, WEIGHTY_SLAM_MULT_PER_STACK,
  RIDER_MULT_PER_STACK, QUICKDRAW_MULT,
  SPRING_POWERED_MULT, THIEF_TRAINING_BEHIND_MULT,
  THIEF_TRAINING_WOULD_CRIT_MULT, VASSALS_CROAK_MULT_PER_STACK,
  RAGING_BOUNCE_MULT, GUIDING_WINDS_MULT_PER_STACK,
  GUIDING_WINDS_WA_MULT_PER_STACK, CIVILIAN_MULT_PER_STACK,
  VAMPIRE_DIVISOR, TOXIN_CASTER_MULT_PER_STACK,
} from '../lib/constants'
import type { BoostAttackType, ProcScalingType } from '../lib/types'

export function calcMinionAbsorptionPotency(summonBoostPct: number, stacks: number): number {
  return Math.round(MINION_ABSORPTION_MULT * (summonBoostPct / 100) * stacks * 10000) / 10000
}

export function calcFrenzyPct(ragePotency: number): number {
  return FRENZY_BASE + FRENZY_RAGE_MULT * ragePotency
}

/** Penance: damage boost scales with missing HP. Bleed procs at ≤35% HP. */
export const PENANCE_HP_THRESHOLD = 35       // percent (≤35% HP → max boost + bleed proc)
export const PENANCE_MAX_BOOST = 0.25        // +25% dmg cap
export const PENANCE_BLEED_POTENCY = 0       // status-only bleed, no damage
export const PENANCE_BLEED_DURATION = 5      // seconds

export interface BoostContext {
  perks: Record<string, number>
  naturalCritChance: number
  jumpBoost: number
  summonCount: number
  ragePotency: number
  bouncePotency: number
  quickdrawPotency: number
  tailwindPotency: number
  tenacity: number
  speedBoost: number
  attackSpeed: number
  inDarkness: boolean
  emotionalState?: string
  level?: number
  mountActive?: boolean
  summonBoostPct?: number
  selectedWeaponArt?: string
  hpFillPct?: number
  hasFireDmg?: boolean
  burnPotency: number
  hasBurn: boolean
  selfDebuffCount: number
  hasMagicDmg?: boolean
  hasMagicOrPhysicalDmg?: boolean
}

export interface BoostDef {
  sourceName: string
  type: 'dmg' | 'heal'
  
  // For simple boosts
  multiplierPerPerk?: number
  condition?: string
  isLevel?: boolean
  
  // For complex boosts - custom calculation function
  calcFn?: (ctx: BoostContext) => { multiplier: number; condition: string } | null
  
  // For boost that only applies to specific attack types
  appliesTo?: BoostAttackType[]
  needsProcCoeff?: boolean

  // How this boost scales with proc coefficient
  procScaling?: ProcScalingType
  // Whether this boost has a user-facing toggle to enable/disable it
  hasToggle?: boolean
  // Base chance (0..1) before proc-coefficient scaling, for boosts with chance-based triggers
  baseProcChance?: number
}

export const BOOST_DEFS: BoostDef[] = [
  // Simple dmg boosts
  {sourceName: 'Blood Thirsty', multiplierPerPerk: BLOOD_THIRSTY_MULT_PER_STACK, type: 'dmg', condition: 'against Bleeding opponents', needsProcCoeff: true},
  {sourceName: 'Venom Spitter', multiplierPerPerk: VENOM_SPITTER_MULT_PER_STACK, type: 'dmg', condition: 'against Poisoned opponents'},
  {sourceName: 'Frostbite', multiplierPerPerk: 0.10, type: 'dmg', condition: 'against Slowed or Frostbitten opponents'},
  {sourceName: 'Gelid Lance', multiplierPerPerk: 0.10, type: 'dmg', condition: 'against Bleeding opponents'},
  {sourceName:'Perfection',multiplierPerPerk: PERFECTION_MULT_PER_STACK, type: 'dmg', condition: 'at max potency',},
  {sourceName:'Stealth',multiplierPerPerk: STEALTH_MULT_PER_STACK, type: 'dmg', condition: "against opponents not targeting you",},
  { sourceName: 'Golden Crits', multiplierPerPerk: GOLDEN_CRITS_MULT_PER_STACK, type: 'dmg', condition: '40% chance on crit', procScaling: 'positiveOnly', hasToggle: true, baseProcChance: GOLDEN_CRITS_BASE_PROC_CHANCE },
  { sourceName: 'Royal Parry', multiplierPerPerk: ROYAL_PARRY_MULT_PER_STACK, type: 'dmg', condition: 'on hits that activated Critical Boost' },
  { sourceName: 'Spell Piercer', multiplierPerPerk: SPELL_PIERCER_MULT_PER_STACK, type: 'dmg', condition: 'on Weapon Arts and Runes that crit' },
  { sourceName: 'Scourge', multiplierPerPerk: SCOURGE_MULT_PER_STACK, condition: 'chance for any hit to Guardbreak', type: 'dmg', needsProcCoeff: true },
  { sourceName: 'Sharpshooter', multiplierPerPerk: SHARPSHOOTER_MULT_PER_STACK, type: 'dmg', condition: 'Hitting from afar', needsProcCoeff: true },
  { sourceName: 'Venom Eater', type: 'dmg', calcFn: (ctx) => { const a = ctx.perks['Venom Eater'] ?? 0; if (a <= 0) return null; return { multiplier: 1 + VENOM_EATER_DMG_MULT_PER_STACK * a, condition: `on Crit against Poisoned opponents` } }, needsProcCoeff: true },
  { sourceName: 'Ferocity', type: 'dmg', calcFn: (ctx) => { const a = ctx.perks['Ferocity'] ?? 0; if (a <= 0 || ctx.tenacity <= 0) return null; const pct = ctx.tenacity * FEROCITY_TENACITY_MULT * a; return { multiplier: 1 + pct / 100, condition: `based on your Tenacity` } } },
  { sourceName: 'Spirit Winds', type: 'dmg', calcFn: (ctx) => { const a = ctx.perks['Spirit Winds'] ?? 0; if (a <= 0 || ctx.tailwindPotency <= 0) return null; const pct = (SPIRIT_WINDS_TAILWIND_MULT * ctx.tailwindPotency + SPIRIT_WINDS_PER_STACK * a) * 100; return { multiplier: 1 + pct / 100, condition: `while you have Tailwind` } } },
  { sourceName: 'Valor', multiplierPerPerk: VALOR_MULT_PER_STACK, type: 'dmg', condition: 'against Taunted opponents' },
  { sourceName: 'Gorecast', multiplierPerPerk: GORECAST_MULT_PER_STACK, type: 'dmg', condition: 'on Weapon Art against Bleeding opponents', appliesTo: ['wa'] },
  { sourceName: 'Guardian Spin', type: 'dmg', calcFn: (ctx) => { const a = ctx.perks['Guardian Spin'] ?? 0; if (a <= 0 || ctx.selectedWeaponArt !== 'Spin') return null; return { multiplier: 1 + GUARDIAN_SPIN_BASE + GUARDIAN_SPIN_MULT_PER_STACK * a, condition: 'for Spin Weapon Art' } }, appliesTo: ['wa'] },
  { sourceName: 'Wild Bolt', type: 'dmg', calcFn: (ctx) => { const a = ctx.perks['Wild Bolt'] ?? 0; if (a <= 0 || ctx.selectedWeaponArt !== 'Laser') return null; return { multiplier: 1 + WILD_BOLT_MULT_PER_STACK * a, condition: 'for Laser Weapon Art' } }, appliesTo: ['wa'] },
  { sourceName: 'Weighty Slam', type: 'dmg', calcFn: (ctx) => { const a = ctx.perks['Weighty Slam'] ?? 0; if (a <= 0 || ctx.selectedWeaponArt !== 'Slam') return null; return { multiplier: 1 + WEIGHTY_SLAM_MULT_PER_STACK * a, condition: 'for Slam Weapon Art' } }, appliesTo: ['wa'] },
  { sourceName: 'Undead Might', multiplierPerPerk: UNDEAD_MIGHT_MULT_PER_STACK, type: 'dmg', condition: 'on Weapon Arts and Runes', appliesTo: ['wa', 'rune'] },
  { sourceName: 'Highlander', multiplierPerPerk: HIGHLANDER_MULT_PER_STACK, type: 'dmg', condition: 'on Weapon Arts and Runes', appliesTo: ['wa', 'rune'] },
  {
    sourceName: 'Toxin Caster',
    type: 'dmg',
    calcFn: (ctx) => {
      const a = ctx.perks['Toxin Caster'] ?? 0
      if (a <= 0 || !ctx.hasMagicDmg) return null
      const poisonPotency = ctx.perks['Poison Potency'] ?? 0
      if (poisonPotency <= 0) return null
      const pct = TOXIN_CASTER_MULT_PER_STACK * poisonPotency * a * 100
      return {
        multiplier: 1 + TOXIN_CASTER_MULT_PER_STACK * poisonPotency * a,
        condition: `${poisonPotency} Poison Potency × ${a} stack × 5%`,
      }
    },
    appliesTo: ['wa', 'rune'],
  },
  {
    sourceName: 'Juggernaut',
    type: 'dmg',
    calcFn: (ctx) => {
      const amt = ctx.perks['Juggernaut'] ?? 0
      if (amt <= 0) return null
      const negSpeed = Math.abs(Math.min(ctx.speedBoost, 0))
      const negAtkSpd = Math.abs(Math.min(ctx.attackSpeed, 0))
      if (negSpeed <= 0 && negAtkSpd <= 0) return null
      const pct = ((negSpeed + negAtkSpd) * amt) / 2
      return {
        multiplier: 1 + pct / 100,
        condition: `-${negSpeed}% spd + -${negAtkSpd}% aspd = +${pct.toFixed(2)}%`,
      }
    },
  },
  { sourceName: 'Rider', type: 'dmg', calcFn: (ctx) => { const a = ctx.perks['Rider'] ?? 0; if (a <= 0 || !ctx.mountActive) return null; return { multiplier: 1 + RIDER_MULT_PER_STACK * a, condition: 'while Mounted · +0.1s stun resist/stack' } } },
  {
    sourceName: 'Quickdraw',
    type: 'dmg',
    calcFn: (ctx) => {
      if (ctx.quickdrawPotency > 0) {
        return {
          multiplier: roundMultiplier(1 + ctx.quickdrawPotency * QUICKDRAW_MULT),
          condition: `while you have Quickdraw`,
        }
      }
      return null
    },
    appliesTo: ['wa', 'rune'],
  },


  // Complex dmg boosts (moved from engine.ts applySpecialBoosts)
  {
    sourceName: 'Primal',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Primal'] ?? 0
      if (stacks > 0 && ctx.naturalCritChance > 0) {
        return {
          multiplier: roundMultiplier(1 + (ctx.naturalCritChance * stacks) / 100),
          condition: `${ctx.naturalCritChance.toFixed(1)}% nat. crit × ${stacks} stack`,
        }
      }
      return null
    },
  },
  {
    sourceName: 'Spring Powered',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Spring Powered'] ?? 0
      if (stacks > 0 && ctx.jumpBoost > 0) {
        return {
          multiplier: roundMultiplier(1 + ctx.jumpBoost * SPRING_POWERED_MULT * stacks),
          condition: `${ctx.jumpBoost} jump boost × ${stacks} stack × 0.75%`,
        }
      }
      return null
    },
  },
  {
    sourceName: 'Thief Training (behind)',
    type: 'dmg',
    calcFn: (ctx) => {
      if ((ctx.perks['Thief Training'] ?? 0) > 0) {
        return { multiplier: THIEF_TRAINING_BEHIND_MULT, condition: 'attacking from behind' }
      }
      return null
    },
  },
  {
    sourceName: 'Thief Training (would-crit bonus)',
    type: 'dmg',
    calcFn: (ctx) => {
      if ((ctx.perks['Thief Training'] ?? 0) > 0) {
        return { multiplier: THIEF_TRAINING_WOULD_CRIT_MULT, condition: 'if attack would have crit without perk' }
      }
      return null
    },
  },
  {
    sourceName: 'Vassals Croak',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Vassals Croak'] ?? 0
      if (stacks > 0 && ctx.summonCount > 0) {
        const clampedCount = Math.floor(ctx.summonCount)
        return {
          multiplier: roundMultiplier(1 + VASSALS_CROAK_MULT_PER_STACK * clampedCount * stacks),
          condition: `${clampedCount} summons × ${stacks} stack × 2%`,
        }
      }
      return null
    },
  },
  {
    sourceName: 'Frenzy',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Frenzy'] ?? 0
      if (stacks > 0 && ctx.ragePotency > 0) {
        const frenzyPct = calcFrenzyPct(ctx.ragePotency) * stacks
        return {
          multiplier: 1 + frenzyPct,
          condition: `Rage active · potency ${Math.round(ctx.ragePotency * 1000) / 1000}`,
        }
      }
      return null
    },
  },
  {
    sourceName: 'Raging Bounce',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Raging Bounce'] ?? 0
      if (stacks > 0 && ctx.bouncePotency > 0) {
        const bouncePct = RAGING_BOUNCE_MULT * ctx.bouncePotency * stacks
        return {
          multiplier: roundMultiplier(1 + bouncePct),
          condition: `while you have Bounce`,
        }
      }
      return null
    },
  },
  {
    sourceName: 'Guiding Winds',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Guiding Winds'] ?? 0
      if (stacks > 0) {
        return { multiplier: 1 + GUIDING_WINDS_MULT_PER_STACK * stacks, condition: 'Moving (at max)' }
      }
      return null
    },
    appliesTo: ['m1', 'm2', 'perk'],
  },
  {
    sourceName: 'Guiding Winds (WA/Rune)',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Guiding Winds'] ?? 0
      if (stacks > 0) {
        return { multiplier: 1 + GUIDING_WINDS_WA_MULT_PER_STACK * stacks, condition: 'Moving (at max)' }
      }
      return null
    },
    appliesTo: ['wa', 'rune'],
  },
  {
    sourceName: 'Civilian',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Civilian'] ?? 0
      if (stacks > 0) {
        return { multiplier: 1 + CIVILIAN_MULT_PER_STACK * stacks, condition: 'on Runes while weapon is unequipped for 3+ seconds' }
      }
      return null
    },
    appliesTo: ['rune'],
  },
  {
    sourceName: 'Vampire',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Vampire'] ?? 0
      if (stacks > 0) {
        const fullPct = stacks / VAMPIRE_DIVISOR
        const dmgPct = ctx.inDarkness ? fullPct : fullPct / 2
        return {
          multiplier: roundMultiplier(1 + dmgPct),
          condition: ctx.inDarkness ? 'in Darkness' : 'in Sunlight',
        }
      }
      return null
    },
  },
  {
    sourceName: 'Smoldering',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Smoldering'] ?? 0
      if (stacks > 0 && ctx.hasBurn) {
        return {
          multiplier: 1 + 0.20 * stacks,
          condition: `while Burning`,
        }
      }
      return null
    },
  },
  {
    sourceName: 'Dark One',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Dark One'] ?? 0
      if (stacks > 0 && ctx.selfDebuffCount > 0) {
        const mult = 1 + (ctx.selfDebuffCount * stacks) / 15
        return {
          multiplier: mult,
          condition: `${ctx.selfDebuffCount} debuff(s) · +${(ctx.selfDebuffCount * stacks / 15 * 100).toFixed(2)}% dmg`,
        }
      }
      return null
    },
  },
  {
    sourceName: 'Minion Absorption',
    type: 'dmg',
    calcFn: (ctx) => {
      const stacks = ctx.perks['Minion Absorption'] ?? 0
      if (stacks <= 0) return null
      const sb = ctx.summonBoostPct ?? 0
      if (sb <= 0) return null
      const potency = calcMinionAbsorptionPotency(sb, stacks)
      return {
        multiplier: roundMultiplier(1 + potency),
        condition: `${sb}% Summon Boost × ${stacks} stack · potency ${potency}`,
      }
    },
  },

  {
    sourceName: 'Penance',
    type: 'dmg',
    calcFn: (ctx) => {
      const amount = ctx.perks['Penance'] ?? 0
      if (amount <= 0) return null
      const hpFill = ctx.hpFillPct ?? 100
      const hpPercent = hpFill / 100
      const boostPerStack = Math.min(PENANCE_MAX_BOOST, PENANCE_MAX_BOOST * (1 - hpPercent) / (1 - PENANCE_HP_THRESHOLD / 100))
      const totalBoost = 1 + boostPerStack * amount
      const pct = Math.round((totalBoost - 1) * 10000) / 100
      return {
        multiplier: totalBoost,
        condition: `${hpFill}% HP → +${pct}% dmg`,
      }
    },
  },

  // Level damage (handled specially in calcBoosts)
  { sourceName: 'Level Damage', multiplierPerPerk: 0, type: 'dmg', isLevel: true },
]

export const BOOST_DEF_MAP = new Map(BOOST_DEFS.map(d => [d.sourceName, d]))

import { DEBUFF_STICKY_DMG_MULT, DEBUFF_DESPAIR_DISPLAY_DIVISOR, DEBUFF_DESPAIR_DISPLAY_MULT, DEBUFF_DESPAIR_DMG_COEFF } from '../lib/constants/debuff-effects'
import { HYPNOTIST_MAGIC_ARMOR_PER_POTENCY } from '../lib/constants/perks'

const ALL_DEF_STAT_KEYS = ['physicalDefense', 'magicDefense', 'fireDefense', 'waterDefense','earthDefense', 'airDefense', 'hexDefense', 'holyDefense',] as const

  export interface DebuffCombatEffect {
    descFn: (potency: number, perks?: Record<string, number>) => string
    damageMult?: (potency: number) => number
   defReduction?: (potency: number) => Partial<Record<typeof ALL_DEF_STAT_KEYS[number], number>>
   typeDamageMult?: (potency: number, perks?: Record<string, number>) => Record<string, number>
  }

export const DEBUFF_COMBAT_EFFECTS: Record<string, DebuffCombatEffect> = {
  Weakness: {
    descFn: (p: number) => {
      const x = Math.round((1 - 1 / (1 + p)) * 10000) / 100
      return `Deal ${x}% less dmg`
    },
    damageMult: (p: number) => 1 / (1 + p),
  },

  Shatter: {
    descFn: (p: number) => `Lose ${(p * 100).toFixed(2)} Armor`,
    defReduction: (p: number) => {
      const amt = p * 100
      return {
        physicalDefense: amt,
        magicDefense: amt,
      }
    },
  },
  Sticky: {
    descFn: (p: number, perks?: Record<string, number>) => {
      const slowPct = Math.round(p * 10000) / 100
      const hasMelting = (perks?.['Melting Slime'] ?? 0) > 0
      if (hasMelting) {
        return `Move ${slowPct}% slower, deals fire and poise damage and take 20% more magic, fire and earth damage.`
      }
      return `Move ${slowPct}% slower · +20% Magic Dmg Taken`
    },
    typeDamageMult: (_p: number, perks?: Record<string, number>) => {
      const base = { magic: DEBUFF_STICKY_DMG_MULT }
      const hasMelting = (perks?.['Melting Slime'] ?? 0) > 0
      if (hasMelting) {
        return { ...base, fire: DEBUFF_STICKY_DMG_MULT, earth: DEBUFF_STICKY_DMG_MULT }
      }
      return base
    },
  },
  'Sticky (Melting Slime)': {
    descFn: (p: number) => {
      const slowPct = Math.round(p * 10000) / 100
      return `Move ${slowPct}% slower and take 20% more magic, fire and earth damage.`
    },
    typeDamageMult: () => ({ magic: DEBUFF_STICKY_DMG_MULT, fire: DEBUFF_STICKY_DMG_MULT, earth: DEBUFF_STICKY_DMG_MULT }),
  },
  'Sticky (Sickness)': {
    descFn: (p: number) => {
      const slowPct = Math.round(p * 10000) / 100
      return `Move ${slowPct}% slower · +20% Hex, Magic & Earth Dmg Taken [Sickness]`
    },
    typeDamageMult: () => ({ magic: DEBUFF_STICKY_DMG_MULT, hex: DEBUFF_STICKY_DMG_MULT, earth: DEBUFF_STICKY_DMG_MULT }),
  },
  'Sticky (Hex Web)': {
    descFn: (p: number) => {
      const slowPct = Math.round(p * 10000) / 100
      return `Move ${slowPct}% slower · +20% Hex & Magic Dmg Taken [Hex Web]`
    },
    typeDamageMult: () => ({ magic: DEBUFF_STICKY_DMG_MULT, hex: DEBUFF_STICKY_DMG_MULT }),
  },
  'Electrical Rend': {
    descFn: (p: number) => `Lose ${(p * 100).toFixed(2)} Armor`,
    defReduction: (p: number) => {
      const amt = p * 100
      return {
        physicalDefense: amt,
        magicDefense: amt,
      }
    },
  },
  Despair: {
    descFn: (p: number) => {
      const pct = Math.round((p / DEBUFF_DESPAIR_DISPLAY_DIVISOR) * DEBUFF_DESPAIR_DISPLAY_MULT * 100) / 100
      return `+${pct}% all damage dealt`
    },
    damageMult: (p: number) => 1 + (p / DEBUFF_DESPAIR_DISPLAY_DIVISOR) * DEBUFF_DESPAIR_DMG_COEFF,
  },
  Frostbite: {
    descFn: () => `+10% Water & Air Dmg Taken`,
    typeDamageMult: () => ({ water: 1.1, air: 1.1 }),
  },
  Hypnotized: {
    descFn: (p: number) => `Lose ${(p * HYPNOTIST_MAGIC_ARMOR_PER_POTENCY).toFixed(1)} Magic Armor`,
    defReduction: (p: number) => ({
      magicDefense: p * HYPNOTIST_MAGIC_ARMOR_PER_POTENCY,
    }),
  },
}

export interface EnemyHpGate {
  hpThreshold: number
  aboveThreshold: boolean
}

export function isEnemyHpGateActive(gate: EnemyHpGate, enemyHpFillPct: number): boolean {
  return gate.aboveThreshold ? enemyHpFillPct > gate.hpThreshold : enemyHpFillPct <= gate.hpThreshold
}

export interface EnemyHpDebuffEffect {
  buffName: string
  getPotency: (perkAmount: number) => number
  duration: number
}

export interface EnemyHpDotBoost {
  dotType: string
  getMultiplier: (perkAmount: number) => number
}

export interface EnemyHpEffectDef {
  perkName: string
  condition: string
  hpGate: EnemyHpGate
  requiresDebuff?: string
  debuff?: EnemyHpDebuffEffect
  dotBoost?: EnemyHpDotBoost
}

export const ENEMY_HP_EFFECT_DEFS: EnemyHpEffectDef[] = [
  {
    perkName: 'Mycotic Bloom',
    condition: 'Poisoned enemies above 50% HP',
    hpGate: { hpThreshold: 50, aboveThreshold: true },
    requiresDebuff: 'Poison',
    debuff: {
      buffName: 'Slowness',
      getPotency: (amt) => 0.2 * amt,
      duration: 5,
    },
  },
  {
    perkName: 'Mycotic Bloom',
    condition: 'Poisoned enemies below 50% HP · +25% Poison dmg per stack',
    hpGate: { hpThreshold: 50, aboveThreshold: false },
    dotBoost: {
      dotType: 'Poison',
      getMultiplier: (amt) => 1 + 0.25 * amt,
    },
  },
]

export function getActiveEnemyHpDebuffs(
  perks: Record<string, number>,
  enemyHpFillPct: number,
  activeDebuffNames: string[],
): Array<{ buffName: string; potency: number; duration: number; condition: string; sourceName: string }> {
  const out: Array<{ buffName: string; potency: number; duration: number; condition: string; sourceName: string }> = []
  for (const def of ENEMY_HP_EFFECT_DEFS) {
    if (!def.debuff) continue
    const amt = perks[def.perkName] ?? 0
    if (amt <= 0) continue
    if (def.requiresDebuff && !activeDebuffNames.includes(def.requiresDebuff)) continue
    if (!isEnemyHpGateActive(def.hpGate, enemyHpFillPct)) continue
    out.push({
      buffName: def.debuff.buffName,
      potency: def.debuff.getPotency(amt),
      duration: def.debuff.duration,
      condition: def.condition,
      sourceName: def.perkName,
    })
  }
  return out
}

export function getEnemyHpDotMultiplier(
  perks: Record<string, number>,
  enemyHpFillPct: number,
  dotType: string,
): number {
  let mult = 1
  for (const def of ENEMY_HP_EFFECT_DEFS) {
    if (!def.dotBoost || def.dotBoost.dotType !== dotType) continue
    const amt = perks[def.perkName] ?? 0
    if (amt <= 0) continue
    if (!isEnemyHpGateActive(def.hpGate, enemyHpFillPct)) continue
    mult *= def.dotBoost.getMultiplier(amt)
  }
  return mult
}

import { PENANCE_HP_THRESHOLD, PENANCE_BLEED_POTENCY, PENANCE_BLEED_DURATION } from './Boost'
import { HYPNOTIST_POTENCY_PER_PERK, HYPNOTIST_DURATION_BASE, HYPNOTIST_DURATION_PER_PERK, FIERY_PURSUIT_BURN_DURATION } from '../lib/constants/perks'
import type { GrantedBuff } from './BuffData'
import { canProc, type ProcCoefficient } from '../lib/types'
import { calcBaseMaxHP } from '../lib/constants/game'
import { getActiveEnemyHpDebuffs } from './enemyHpEffects'

export interface AutoDebuffInput {
  existingBuffNames: string[]
  playerBuffNames: string[]
  perks: Record<string, number>
  hpFill: number
  level: number
  protection: number
  selectedWAProcCoefficient?: ProcCoefficient
  enemyHpFillPct: number
  hasMagicDmg?: boolean
  hasMagicOrPhysicalDmg?: boolean
}

export function calcActualHpFillPct(
  hpFill: number,
  level: number,
  protection: number
): number {
  if (protection >= 0) return hpFill
  const baseMaxHP = calcBaseMaxHP(level ?? 80)
  const effMaxHP = Math.max(Math.round(baseMaxHP * 0.1), baseMaxHP + Math.round(protection))
  return Math.min(100, hpFill * effMaxHP / baseMaxHP)
}

export function getAutoDebuffs(input: AutoDebuffInput): GrantedBuff[] {
  const debuffs: GrantedBuff[] = []
  const { existingBuffNames, playerBuffNames, perks, hpFill, level, protection, selectedWAProcCoefficient, enemyHpFillPct } = input

  const hasExhaust = playerBuffNames.includes('Exhaust')
  const hasBurn = existingBuffNames.includes('Burn')
  const exhaustCanProc = canProc(selectedWAProcCoefficient)

  if (hasExhaust && !hasBurn && exhaustCanProc) {
    debuffs.push({
      buffName: 'Burn',
      potency: 0,
      duration: 5,
      condition: 'On hit during Exhaust',
      sourceName: 'Exhaust',
      sourceType: 'perk',
    })
  }

  const penanceAmt = perks['Penance'] ?? 0
  if (penanceAmt > 0) {
    const actualHpPct = calcActualHpFillPct(hpFill, level, protection)
    if (actualHpPct <= PENANCE_HP_THRESHOLD && !existingBuffNames.includes('Bleed')) {
      debuffs.push({
        buffName: 'Bleed',
        potency: PENANCE_BLEED_POTENCY,
        duration: PENANCE_BLEED_DURATION,
        condition: `50% chance per hit · only while HP ≤ ${PENANCE_HP_THRESHOLD}%`,
        sourceName: 'Penance',
        sourceType: 'perk',
      })
    }
  }

  const meltingShredAmt = perks['Melting Shred'] ?? 0
  if (meltingShredAmt > 0) {
    const dotDebuffs = ['Bleed', 'Burn', 'Poison', 'Slowness']
    const hasDotActive = dotDebuffs.some(d => existingBuffNames.includes(d))
    if (hasDotActive && !existingBuffNames.includes('Anti Heal')) {
      debuffs.push({
        buffName: 'Anti Heal',
        potency: 0.5,
        duration: 0,
        condition: 'Active while target has your DoT',
        sourceName: 'Melting Shred',
        sourceType: 'perk',
      })
    }
  }

  const fpAmt = perks['Fungal Prototype'] ?? 0
  if (fpAmt > 0 && !existingBuffNames.includes('Poison')) {
    debuffs.push({
      buffName: 'Poison',
      potency: fpAmt,
      duration: 0,
      condition: 'Active while WA/Rune hit procced Fungal Prototype',
      sourceName: 'Fungal Prototype',
      sourceType: 'perk',
    })
  }

  const vsAmt = perks['Venom Spitter'] ?? 0
  if (vsAmt > 0 && !existingBuffNames.includes('Poison')) {
    debuffs.push({
      buffName: 'Poison',
      potency: vsAmt,
      duration: 0,
      condition: 'Venom Spitter finisher applies Poison',
      sourceName: 'Venom Spitter',
      sourceType: 'perk',
    })
  }

  const toxinCasterAmt = perks['Toxin Caster'] ?? 0
  if (toxinCasterAmt > 0 && input.hasMagicDmg && !existingBuffNames.includes('Poison')) {
    debuffs.push({
      buffName: 'Poison',
      potency: 0,
      duration: 0,
      condition: 'Magic damage from WA or Rune applies Poison',
      sourceName: 'Toxin Caster',
      sourceType: 'perk',
    })
  }

  const gorecastAmt = perks['Gorecast'] ?? 0
  if (gorecastAmt > 0 && input.hasMagicOrPhysicalDmg && !existingBuffNames.includes('Bleed')) {
    debuffs.push({
      buffName: 'Bleed',
      potency: 0,
      duration: 5,
      condition: 'On Weapon Art hit (deals Magic or Physical damage)',
      sourceName: 'Gorecast',
      sourceType: 'perk',
    })
  }

  const bellowingAmt = perks['Bellowing Ember'] ?? 0
  if (bellowingAmt > 0) {
    const actualHpPct = calcActualHpFillPct(hpFill, level, protection)
    const threshold = 40 + 5 * (bellowingAmt - 1)
    if (actualHpPct <= threshold && !existingBuffNames.includes('Burn')) {
      debuffs.push({
        buffName: 'Burn',
        potency: 0,
        duration: 5,
        condition: `35% chance per hit · only while HP ≤ ${threshold}%`,
        sourceName: 'Bellowing Ember',
        sourceType: 'perk',
      })
    }
  }

  const frostbiteAmt = perks['Frostbite'] ?? 0
  if (frostbiteAmt > 0 && !existingBuffNames.includes('Slowness')) {
    debuffs.push({
      buffName: 'Slowness',
      potency: 0.5 * frostbiteAmt,
      duration: 0,
      condition: `${10 * frostbiteAmt}% chance per hit · Potency = 0.5 × ${frostbiteAmt}`,
      sourceName: 'Frostbite',
      sourceType: 'perk',
    })
  }

  const gelidLanceAmt = perks['Gelid Lance'] ?? 0
  if (gelidLanceAmt > 0) {
    const hasSlow = existingBuffNames.includes('Slowness') || debuffs.some(d => d.buffName === 'Slowness')
    const hasBleed = existingBuffNames.includes('Bleed') || debuffs.some(d => d.buffName === 'Bleed')
    if (hasSlow && !hasBleed) {
      debuffs.push({
        buffName: 'Bleed',
        potency: 0,
        duration: 5,
        condition: 'Applies Bleed when Slowness is applied',
        sourceName: 'Gelid Lance',
        sourceType: 'perk',
      })
    }
  }

  const weakeningAmt = perks['Weakening'] ?? 0
  if (weakeningAmt > 0 && !existingBuffNames.includes('Weakness')) {
    debuffs.push({
      buffName: 'Weakness',
      potency: 0.2 * weakeningAmt,
      duration: 5,
      condition: `${5 * weakeningAmt}% chance per hit · Potency = 0.2 × ${weakeningAmt}`,
      sourceName: 'Weakening',
      sourceType: 'perk',
    })
  }

  const sunburnAmt = perks['Sunburn'] ?? 0
  if (sunburnAmt > 0 && !existingBuffNames.includes('Burn')) {
    const burnChance = 24 + 6 * sunburnAmt
    debuffs.push({
      buffName: 'Burn',
      potency: 0,
      duration: 5,
      condition: `${burnChance}% chance on Holy attacks`,
      sourceName: 'Sunburn',
      sourceType: 'perk',
    })
  }

  const fieryPursuitAmt = perks['Fiery Pursuit'] ?? 0
  if (fieryPursuitAmt > 0 && exhaustCanProc && !existingBuffNames.includes('Burn')) {
    debuffs.push({
      buffName: 'Burn',
      potency: 0,
      duration: FIERY_PURSUIT_BURN_DURATION,
      condition: 'On dash before Weapon Art',
      sourceName: 'Fiery Pursuit',
      sourceType: 'perk',
    })
  }

  const hypnotistAmt = perks['Hypnotist'] ?? 0
  if (hypnotistAmt > 0 && exhaustCanProc && !existingBuffNames.includes('Hypnotized')) {
    debuffs.push({
      buffName: 'Hypnotized',
      potency: HYPNOTIST_POTENCY_PER_PERK * hypnotistAmt,
      duration: HYPNOTIST_DURATION_BASE + HYPNOTIST_DURATION_PER_PERK * hypnotistAmt,
      condition: 'On WA or Rune hit · Potency = 0.1 × ' + hypnotistAmt,
      sourceName: 'Hypnotist',
      sourceType: 'perk',
    })
  }

  const enemyHpDebuffs = getActiveEnemyHpDebuffs(perks, enemyHpFillPct, existingBuffNames)
  for (const d of enemyHpDebuffs) {
    if (existingBuffNames.includes(d.buffName)) continue
    debuffs.push({
      buffName: d.buffName,
      potency: d.potency,
      duration: d.duration,
      condition: d.condition,
      sourceName: d.sourceName,
      sourceType: 'perk',
    })
  }

  return debuffs
}

